16	const PROCESSING_FEE = 5;
17	const BASE_PREMIUMS: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	};
23	const FIRST_INSURANCE_SURCHARGE = 0.1;
24	
25	// Rounds up in MHPCO's favor, guarding against floating-point drift
26	// (e.g. 197.50000000001 should round to 198, not be inflated by noise).
27	const roundUpInFavor = (amount: number): number =>
28	  Math.ceil(Number(amount.toFixed(6)));
29	
30	const itemPremium = (item: Item): number =>
31	  BASE_PREMIUMS[item.type] * (1 + FIRST_INSURANCE_SURCHARGE);
32	
33	export const quote = (customer: Customer, items: Item[]): QuoteResult => {
34	  const basePremiumTotal = items.reduce(
35	    (total, item) => total + itemPremium(item),
36	    0,
37	  );
38	  const exactPremium = basePremiumTotal + PROCESSING_FEE;
39	  return { premium: roundUpInFavor(exactPremium) };
40	};
